import{c as a,Q as o,j as t,m as s}from"./chunks/framework.iD28w_5a.js";const u=JSON.parse('{"title":"000-env-toolchain-3 · 环境搭建","description":"","frontmatter":{"title":"000-env-toolchain-3 · 环境搭建"},"headers":[],"relativePath":"hands-on/000-env-toolchain-3.md","filePath":"hands-on/000-env-toolchain-3.md","lastUpdated":1779686691000}'),d={name:"hands-on/000-env-toolchain-3.md"};function n(c,e,r,i,p,l){return o(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="_000-3-·-测试框架与完整构建验证" tabindex="-1">000-3 · 测试框架与完整构建验证 <a class="header-anchor" href="#_000-3-·-测试框架与完整构建验证" aria-label="Permalink to &quot;000-3 · 测试框架与完整构建验证&quot;">​</a></h1><blockquote><p><strong>本篇目标</strong>：实现自研的轻量测试框架， 编写冒烟测试验证框架工作正常， 跑通从源码到测试的完整开发循环。</p><p><strong>完成后的效果</strong>：<code>make test</code> 全绿通过冒烟测试， 测试框架的 Host 模式和 QEMU 模式双轨可用。</p><p><strong>前置</strong>：完成 000-1（工具链 + CMake）和 000-2（MBR 存根 + QEMU）。</p></blockquote><hr><h2 id="前言-为什么从第一个-tag-就要有测试" tabindex="-1">前言：为什么从第一个 tag 就要有测试 <a class="header-anchor" href="#前言-为什么从第一个-tag-就要有测试" aria-label="Permalink to &quot;前言：为什么从第一个 tag 就要有测试&quot;">​</a></h2><p>写 OS 内核没有测试是非常恐怖的事情 ——你改了一行代码，内核跑起来直接 triple fault， 但你完全不知道是哪一行改坏了， 因为内核里连 <code>printf</code> 都没有。 传统 OS 教程几乎不提测试： xv6 完全没有测试框架，所有验证都靠手动运行和目测输出。 这在只有几百行代码的教学项目里还行， 但 Cinux 计划发展到几千行代码的时候， 没有测试就太危险了。</p><p>Cinux 从第一个 tag 就引入了自研的轻量测试框架， 支持 Host 模式（在 Linux 上用 g++ 编译运行） 和 QEMU 模式（在内核里通过串口输出）， 让逻辑性的 bug 在 Host 端就能被捕获。 Host 模式的优势在于： 不需要内核就能测试纯逻辑 （比如 kprintf 的格式化、GDT 描述符编码、内存管理算法）， QEMU 模式则测试需要硬件交互的部分 （比如中断处理、驱动初始化）。</p><p>这种双模式方案的巧妙之处在于： 同一个测试用例的接口完全统一（<code>TEST</code> 和 <code>ASSERT_*</code> 宏）， 底层实现通过条件编译切换， 开发者不需要关心运行环境差异。</p><hr><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="为什么不能用-google-test-catch2" tabindex="-1">为什么不能用 Google Test / Catch2 <a class="header-anchor" href="#为什么不能用-google-test-catch2" aria-label="Permalink to &quot;为什么不能用 Google Test / Catch2&quot;">​</a></h3><p>标准的 C++ 测试框架（Google Test、Catch2、doctest） 都假设了一个 hosted 环境： 它们使用 <code>malloc</code> 动态分配内存、 依赖 <code>&lt;iostream&gt;</code> 做输出、 使用 <code>std::exception</code> 做错误传播、 甚至需要多线程支持。 在内核的 freestanding 环境里， 这些东西统统不存在。</p><p>有人可能会说&quot;可以用 Google Test 的 freestanding 裁剪版&quot;。 理论上可行，但实际操作中： Google Test 即使裁剪后仍然很重， 而且它的构建集成对内核项目来说是个麻烦事 ——你需要让 CMake 在两种完全不同的编译环境下 （内核的 freestanding 和测试的 hosted） 同时工作，复杂度飙升。</p><p>更简单的方案是用 <code>assert()</code> + 手写 main 来做最原始的测试， 但这种方式没有测试发现和注册机制， 测多了之后管理测试列表非常痛苦 ——每加一个测试就要手动在 main 里加一行调用， 忘记加就等于白写。</p><p>Cinux 的自研框架在两者之间取了一个平衡点： 极简（单头文件，零动态内存，零异常依赖）， 但功能足够（自动注册、多种断言宏、Host/QEMU 双模式）。</p><h3 id="test-宏的自动注册原理" tabindex="-1">TEST 宏的自动注册原理 <a class="header-anchor" href="#test-宏的自动注册原理" aria-label="Permalink to &quot;TEST 宏的自动注册原理&quot;">​</a></h3><p>框架的核心设计是用宏来定义测试用例 （<code>TEST(&quot;name&quot;) { ... }</code>）， 利用 C++ 静态对象的构造函数 在 <code>main</code> 函数之前执行的特性， 每个 <code>TEST</code> 块会自动把自己的函数指针注册到全局数组里。</p><p>这里有一个经典的 C 预处理器陷阱： <code>__LINE__</code> 不能直接和标识符拼接。 <code>##</code> 运算符（token pasting）不会先展开它的操作数， 所以 <code>_test_fn_##__LINE__</code> 会得到字面的 <code>_test_fn___LINE__</code> 而不是 <code>_test_fn_42</code>。 解决方法是增加一层间接： 定义一个 <code>_TEST_CAT(a, b)</code> 宏， 里面再套一个 <code>_TEST_CAT2(a, b)</code> 宏做实际的 <code>##</code> 拼接。 在调用 <code>_TEST_CAT</code> 的时候 <code>__LINE__</code> 已经被展开成了数字， 然后 <code>_TEST_CAT2</code> 才真正执行拼接。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TEST(&quot;name&quot;) { body } 展开过程：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 声明静态函数 _test_fn_42()</span></span>
<span class="line"><span>2. 定义静态结构体 _TestAutoReg_42</span></span>
<span class="line"><span>   - 构造函数调用 _register_test(&quot;name&quot;, file, line, _test_fn_42)</span></span>
<span class="line"><span>3. 定义静态变量 _test_reg_42（触发构造函数 -&gt; 自动注册）</span></span>
<span class="line"><span>4. 定义静态函数 _test_fn_42() { body }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>关键：_TEST_CAT 两层间接展开</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  _TEST_CAT(_test_fn_, __LINE__)</span></span>
<span class="line"><span>  -&gt; _TEST_CAT2(_test_fn_, 42)    // __LINE__ 在这一步被展开</span></span>
<span class="line"><span>  -&gt; _test_fn_42                  // ## 在这里执行拼接</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h3 id="assert-宏的设计取舍" tabindex="-1">ASSERT 宏的设计取舍 <a class="header-anchor" href="#assert-宏的设计取舍" aria-label="Permalink to &quot;ASSERT 宏的设计取舍&quot;">​</a></h3><p>断言宏使用 <code>do { ... } while(0)</code> 包裹 ——这是 C/C++ 宏的标准防御性写法， 确保宏在使用时后面能正确加分号， 不会在 if-else 语境里出问题。</p><p>失败时的处理策略是： 打印测试名和断言位置（用 <code>#expr</code> 把表达式原样字符串化）， 递增全局失败计数，然后 <code>return</code>—— 注意是 <code>return</code> 而不是 <code>abort</code>， 这样当前测试会提前退出， 但不会影响后续测试的执行。</p><p>这个设计有一个已知的简化缺陷： <code>RUN_ALL_TESTS</code> 的循环在每次测试执行后都打印 <code>[PASS]</code>， 即使测试中途断言失败了也会打印。 这是因为循环里没有 per-test 的状态追踪 ——要精确追踪需要在每个测试前后保存和比较失败计数。 对于 tag 000 的冒烟测试来说完全够用，后续版本可以改进。</p><hr><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-5-搭建测试框架" tabindex="-1">Step 5: 搭建测试框架 <a class="header-anchor" href="#step-5-搭建测试框架" aria-label="Permalink to &quot;Step 5: 搭建测试框架&quot;">​</a></h3><p><strong>目标</strong>：实现自研的轻量测试框架， 编写一个冒烟测试验证框架工作正常。</p><p><strong>设计思路</strong>：框架的核心设计是： 用宏来定义测试用例（<code>TEST(&quot;name&quot;) { ... }</code>）， 用宏来写断言（<code>ASSERT_EQ</code>, <code>ASSERT_TRUE</code> 等）， 然后在 main 函数里调用 <code>RUN_ALL_TESTS()</code> 自动运行所有注册的测试。 框架支持两种运行模式： Host 模式和 QEMU 模式。 Host 模式用 <code>-DCINUX_HOST_TEST</code> 宏启用， 测试代码用系统 g++ 编译在 Linux 上运行， <code>printf</code> 输出结果，<code>abort()</code> 处理致命错误。 QEMU 模式下测试代码被编译进内核， 通过串口输出结果。 两种模式共享同一套 <code>TEST</code> 和 <code>ASSERT</code> 宏接口， 通过条件编译切换底层实现。</p><p><strong>实现约束</strong>：</p><p>框架头文件路径是 <code>test/framework/test_framework.h</code>。 它需要定义以下核心组件：</p><p>一个函数指针类型 <code>_test_fn_t</code> 表示测试函数， 一个结构体 <code>_TestEntry</code> （包含名字、文件名、行号、函数指针） 表示测试条目， Host 模式下使用静态数组 <code>_test_registry[]</code>（最多 256 个条目） 通过全局构造函数自动注册， 统计变量 <code>_tests_passed</code> 和 <code>_tests_failed</code> 记录通过和失败的测试数量， <code>TEST</code> 宏展开为一个静态函数定义加一个自动注册类， <code>ASSERT_*</code> 宏使用 <code>do { ... } while(0)</code> 包裹， 失败时打印文件名和行号， 递增失败计数，并 return 跳出当前测试， <code>RUN_ALL_TESTS</code> 函数遍历注册数组， 依次调用每个测试函数， 运行完毕后打印 <code>[SUITE PASSED]</code> 或 <code>[SUITE FAILED]</code>。</p><p>头文件使用单头文件库模式（stb 风格）： 通过 <code>TEST_FRAMEWORK_IMPL</code> 宏控制全局变量的定义。 在 <code>test_smoke.cpp</code> 的第一行定义这个宏， 然后 <code>#include</code> 测试框架头文件， 全局变量就只会被定义一次。</p><p><code>test/CMakeLists.txt</code> 配置 Host 模式的测试： 创建可执行目标 <code>test_smoke</code>， 源文件只有 <code>test_smoke.cpp</code>， 添加 <code>CINUX_HOST_TEST</code> 编译定义， 设置包含目录（框架头文件和内核头文件）， 注册到 CTest。 需要在顶层 CMakeLists.txt 中用 <code>CINUX_BUILD_TESTS</code> option 控制 test 子目录的引入。</p><p>冒烟测试（<code>test/unit/test_smoke.cpp</code>） 不测试任何内核逻辑，只验证框架本身： 四个测试用例分别覆盖： 整数比较（<code>ASSERT_EQ/TRUE/FALSE/GT/GE/LE/LT</code>）、 边界值（零和负数，以及 <code>ASSERT_NE</code> 不等断言）、 指针断言（<code>ASSERT_NULL/NOT_NULL</code>）、 以及一个空的占位测试（预留未来扩展字符串相关断言）。</p><p><strong>踩坑预警</strong>：<code>TEST</code> 宏的展开有一个经典的 C 预处理器陷阱 ——<code>__LINE__</code> 不能直接和标识符拼接 （<code>##</code> 运算符不展开它的操作数）， 需要用两层宏间接展开。 具体做法是定义一个 <code>_TEST_CAT(a, b)</code> 宏， 里面再套一个 <code>_TEST_CAT2(a, b)</code> 宏做实际的 <code>##</code> 拼接。 这个问题不处理好， 所有测试用例会生成同一个函数名， 编译直接报重复定义。</p><p>另外，<code>RUN_ALL_TESTS</code> 里的 per-test 通过/失败追踪需要仔细设计 ——每个测试函数失败时 return 而不是 continue， 所以在循环里判断是否失败的方法是 &quot;失败计数是否有变化&quot; 而不是&quot;当前测试是否返回了某个状态&quot;。 当前框架简化了这个问题： 每次循环末尾直接打印 PASS， 如果测试中途断言失败就已经 return 了不会到达这一步。</p><p><strong>验证</strong>：运行 <code>make test</code> （或者 <code>cd build &amp;&amp; ctest --output-on-failure</code>）， 终端应该打印测试运行器标题、测试数量、 每个测试的 <code>[PASS]</code> 标记， 最后显示 <code>Results: 4 passed, 0 failed</code> 和 <code>[SUITE PASSED]</code>。</p><hr><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>完整的从零开始的构建流程如下：</p><p>首先确保工具链已安装（Step 1 的检查脚本通过）， 然后在项目根目录执行： 创建 build 目录，进入 build 目录， 运行 CMake configure（指定 Debug 模式和开启测试）， 最后 <code>make</code> 编译。 编译成功后，<code>make run</code> 启动 QEMU，<code>make test</code> 跑测试。</p><p>构建命令：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mkdir build &amp;&amp; cd build</span></span>
<span class="line"><span>cmake -DCMAKE_BUILD_TYPE=Debug -DCINUX_BUILD_TESTS=ON ..</span></span>
<span class="line"><span>make</span></span>
<span class="line"><span>make test</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>如果需要调试，可以用 <code>make run-debug</code> 启动 QEMU （会在端口 1234 开 GDB server，启动后暂停等待连接）， 然后在另一个终端用 GDB 连接： 加载内核 ELF 符号文件， 连接 <code>target remote :1234</code>， 设置断点，<code>continue</code> 继续。 Tag 000 的 MBR 存根没有符号信息（纯汇编裸二进制）， GDB 调试在后续章节才有实际用途，但可以先验证 GDB 能连上。</p><p>QEMU 的常用启动参数说明： <code>-m</code> 指定模拟内存大小， <code>-serial stdio</code> 把虚拟串口映射到宿主终端 （后续章节的 <code>kprintf</code> 输出会出现在这里）， <code>-no-reboot</code> 让 QEMU 在 triple fault 时退出而不是重启， <code>-no-shutdown</code> 让 QEMU 在执行 <code>hlt</code> 后保持运行而不自动退出， <code>-s</code> 开启 GDB stub， <code>-S</code> 启动后暂停。</p><hr><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><h3 id="问题-测试编译失败-报-undefined-reference-to-test-registry" tabindex="-1">问题：测试编译失败，报 undefined reference to _test_registry <a class="header-anchor" href="#问题-测试编译失败-报-undefined-reference-to-test-registry" aria-label="Permalink to &quot;问题：测试编译失败，报 undefined reference to _test_registry&quot;">​</a></h3><p>确保 <code>test_smoke.cpp</code> 文件开头定义了 <code>#define TEST_FRAMEWORK_IMPL</code> 再 <code>#include &quot;test_framework.h&quot;</code>。 这个宏控制全局变量的定义， 不定义的话只有声明没有定义，链接器会报未定义引用。</p><h3 id="问题-测试运行时所有测试都是-pass-但预期有失败" tabindex="-1">问题：测试运行时所有测试都是 PASS，但预期有失败 <a class="header-anchor" href="#问题-测试运行时所有测试都是-pass-但预期有失败" aria-label="Permalink to &quot;问题：测试运行时所有测试都是 PASS，但预期有失败&quot;">​</a></h3><p>检查 <code>ASSERT_*</code> 宏是否正确使用了 <code>do { ... } while(0)</code> 包裹。 如果宏展开后有问题（比如分号被吃掉了）， 断言可能不会真正执行。 另外确认 <code>_tests_failed</code> 变量是否被正确定义 （需要在 <code>TEST_FRAMEWORK_IMPL</code> 宏保护下）。</p><h3 id="问题-cmake-configure-找不到测试目标" tabindex="-1">问题：CMake configure 找不到测试目标 <a class="header-anchor" href="#问题-cmake-configure-找不到测试目标" aria-label="Permalink to &quot;问题：CMake configure 找不到测试目标&quot;">​</a></h3><p>确认顶层 CMakeLists.txt 里 <code>CINUX_BUILD_TESTS</code> 被设为 ON： <code>cmake -DCINUX_BUILD_TESTS=ON ..</code>。 默认不引入 test 子目录， 需要显式开启。</p><hr><h2 id="本篇小结" tabindex="-1">本篇小结 <a class="header-anchor" href="#本篇小结" aria-label="Permalink to &quot;本篇小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>要点</th></tr></thead><tbody><tr><td>测试框架设计</td><td>单头文件，零动态内存，零异常依赖</td></tr><tr><td>TEST 宏</td><td>两层间接展开解决 <code>__LINE__</code> + <code>##</code> 陷阱</td></tr><tr><td>ASSERT 宏</td><td><code>do { ... } while(0)</code> 包裹，失败时 return</td></tr><tr><td>Host/QEMU 双模式</td><td><code>CINUX_HOST_TEST</code> 条件编译切换底层实现</td></tr><tr><td><code>TEST_FRAMEWORK_IMPL</code></td><td>stb 风格单头文件，控制全局变量定义</td></tr><tr><td>CTest 集成</td><td><code>add_test</code> 注册，<code>ctest --output-on-failure</code> 运行</td></tr><tr><td>冒烟测试</td><td>4 个测试用例：整数、边界值、指针、占位</td></tr></tbody></table><p>到这里，tag 000 的全部工作就完成了： 环境搭建、CMake 构建系统、MBR 存根、测试框架。 从安装工具链到在 QEMU 里看到第一个字符输出， 再到跑通自研测试框架 ——这些都是后续所有 tag 的基础。 下一章我们将真正进入 MBR bootloader 的开发： BIOS 中断、磁盘读取、stage2 加载。 准备好进入实模式的世界吧。</p><hr><h2 id="扩展方向" tabindex="-1">扩展方向 <a class="header-anchor" href="#扩展方向" aria-label="Permalink to &quot;扩展方向&quot;">​</a></h2><ul><li>给测试框架加一个 <code>ASSERT_STREQ(str1, str2)</code> 宏， 用 <code>strcmp</code> 比较字符串，需要处理空指针的情况</li><li>给 RUN_ALL_TESTS 加 per-test 的通过/失败追踪， 修复当前&quot;失败的测试也打印 PASS&quot;的问题</li><li>尝试把测试框架改成 QEMU 模式 （定义 QEMU 版的 <code>serial_printf</code> stub）， 让测试在内核环境里通过串口输出</li><li>给 <code>build_image.sh</code> 加 stage2 写入逻辑 （第二个 <code>dd</code> 命令），为 tag 001 做准备</li><li>尝试把构建系统迁移到用 <code>add_custom_command</code> 生成依赖图， 让 CMake 自动跟踪 <code>mbr.bin</code> -&gt; <code>cinux.img</code> 的依赖关系， 修改源码后只需要 <code>make</code> 就能自动重跑 objcopy + dd</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>OSDev Wiki — <a href="https://wiki.osdev.org/Bare_Bones" target="_blank" rel="noreferrer">Bare Bones</a>: freestanding 环境和编译 flag 参考</li><li>Intel SDM — Volume 1: Basic Architecture， 描述实模式寄存器和 red zone 约束</li><li>OSDev Wiki — <a href="https://wiki.osdev.org/MBR_(x86)" target="_blank" rel="noreferrer">MBR (x86)</a>: MBR 格式和 BIOS 引导行为</li><li>OSDev Wiki — <a href="https://wiki.osdev.org/Real_Mode" target="_blank" rel="noreferrer">Real Mode</a>: 实模式寻址机制</li></ul>`,61)])])}const h=a(d,[["render",n]]);export{u as __pageData,h as default};
